
(function(window, document){
  var IGDC = window.IGDC = (window.IGDC||{});
  if(IGDC.__payReady) return; IGDC.__payReady = true;

  // Payment open with graceful fallback
  IGDC.openPayment = async function(opts){
    opts = opts || {}; var method = (opts.method||"card");
    // 1) Ask backend status (if available)
    var status = await IGDC.status();
    var enabled = false;
    try{
      enabled = !!(status && status.payment && status.payment[method]);
    }catch(e){ enabled = false; }

    // 2) If not enabled, show "서비스 준비중입니다"
    if(!enabled){
      var n = document.createElement("div");
      n.innerHTML = '<div style="font:600 16px/1.4 system-ui,Segoe UI,Apple SD Gothic Neo,Malgun Gothic,Roboto,sans-serif">서비스 준비중입니다</div>' +
        '<div style="margin-top:6px;color:#666;font:13px/1.5 system-ui">아직 '+ method +' 결제 연동이 완료되지 않았습니다.<br/>도메인 오픈 및 키 발급 후 자동 활성화됩니다.</div>';
      IGDC.openModal(n);
      return;
    }

    try{
      // 3) Attempt server checkout
      var r = await fetch("/api/payment/checkout", {
        method:"POST",
        headers: {"Content-Type":"application/json"},
        credentials:"include",
        body: JSON.stringify({ method: method, amount: opts.amount, currency: opts.currency||"KRW", itemId: opts.itemId||"", meta: opts.meta||{} })
      });
      if(r.status === 503){
        // backend intentionally disabled → show prepared message
        var n2 = document.createElement("div");
        n2.innerHTML = '<div style="font:600 16px/1.4 system-ui">서비스 준비중입니다</div>' +
          '<div style="margin-top:6px;color:#666;font:13px/1.5 system-ui">결제 게이트웨이가 아직 연결되지 않았습니다.</div>';
        IGDC.openModal(n2);
        return;
      }
      var j = await r.json();
      // Minimal mock flow
      var box = document.createElement("div");
      box.innerHTML = '<div style="font:700 16px/1.4 system-ui">결제 진행</div>' +
        '<div style="margin-top:8px;font:13px/1.6 system-ui">방식: '+ method.toUpperCase() +
        (opts.amount ? ' · 금액: '+ opts.amount + (opts.currency||"KRW") : "") + '</div>' +
        '<div style="margin-top:8px"><button id="igdc-mock-complete" style="padding:8px 12px;border-radius:10px;border:1px solid #ddd;background:#0b2a6f;color:#fff;font-weight:700">모의 결제 완료</button></div>';
      IGDC.openModal(box);
      var doneBtn = box.querySelector("#igdc-mock-complete");
      if(doneBtn){
        doneBtn.addEventListener("click", function(){
          try{ if(window.SNTracker && SNTracker.purchase){ SNTracker.purchase({method:method, amount:opts.amount||0, itemId: opts.itemId||""}); } }catch(e){}
          alert("결제가 완료되었습니다 (모의).");
          document.getElementById("igdc-modal").style.display="none";
        });
      }
    }catch(e){
      var n3 = document.createElement("div");
      n3.innerHTML = '<div style="font:600 16px/1.4 system-ui">결제 연결 오류</div><div style="margin-top:6px;color:#c00">네트워크 또는 서버 연결을 확인해주세요.</div>';
      IGDC.openModal(n3);
    }
  };

  // Auto-bind for elements with data-pay attributes
  function autoBind(){
    Array.prototype.forEach.call(document.querySelectorAll("[data-pay]"), function(el){
      if(el.__igdcPayBound) return;
      el.__igdcPayBound = true;
      el.addEventListener("click", function(){
        var method = el.getAttribute("data-method") || "card";
        var amount = parseFloat(el.getAttribute("data-amount")||"0")||0;
        var currency = el.getAttribute("data-currency") || "KRW";
        var itemId = el.getAttribute("data-item") || "";
        IGDC.openPayment({method, amount, currency, itemId});
      });
    });
  }
  document.addEventListener("DOMContentLoaded", autoBind);
  document.addEventListener("IGDC_PAY_LAUNCH", function(){ IGDC.openPayment({}); });

})(window, document);
